// AMBIL ID DARI VIEW PAGE
$id = $params["id"];

// QUERY DATA
$sql = "
SELECT 
  daftar.madrasah,
  daftar.pengajuan,
  daftar.`nomor surat`,
  jenis_surat.jenis_surat,
  jenis_surat.hp_petugas,
  daftar.status,
  CONCAT(
    'B-            /                           ./PP.006/',
    LPAD(MONTH(daftar.`tgl surat`), 2, '0'),
    '/',
    YEAR(daftar.`tgl surat`)
  ) AS nomor_surat_madrasah,
  CONCAT(
    RIGHT(DATE(daftar.`tgl surat`), 2), ' ',
    CASE MONTHNAME(daftar.`tgl surat`)
      WHEN 'January' THEN 'Januari'
      WHEN 'February' THEN 'Februari'
      WHEN 'March' THEN 'Maret'
      WHEN 'April' THEN 'April'
      WHEN 'May' THEN 'Mei'
      WHEN 'June' THEN 'Juni'
      WHEN 'July' THEN 'Juli'
      WHEN 'August' THEN 'Agustus'
      WHEN 'September' THEN 'September'
      WHEN 'October' THEN 'Oktober'
      WHEN 'November' THEN 'November'
      WHEN 'December' THEN 'Desember'
    END,
    ' ',
    YEAR(daftar.`tgl surat`)
  ) AS tgl_surat_full,
  profil.`Nomor Telpon`
FROM daftar
INNER JOIN profil ON daftar.nsm = profil.NSM
INNER JOIN jenis_surat ON daftar.pengajuan = jenis_surat.id
WHERE daftar.id = ".$id;

$rs = DB::Query($sql);
$datax = $rs->fetchAssoc();

// SUSUN PESAN WA
$pesan  = "Assalamu'alaikum Bapak/Ibu dari Madrasah ".$datax["madrasah"].",\n\n";
$pesan .= "Bersama ini kami sampaikan bahwa permohonan ".$datax["jenis_surat"]."\n";
$pesan .= "Nomor: ".$datax["nomor surat"]."\n";
$pesan .= "Status: ".$datax["status"]."\n\n";
$pesan .= "Apabila ada kendala silakan hubungi nomor/WA ".$datax["hp_petugas"].".\n";
$pesan .= "Terima kasih.";

// FORMAT NOMOR TELEPON
$nomor = preg_replace('/[^0-9]/', '', $datax["Nomor Telpon"]);
if(substr($nomor, 0, 1) == '0') {
    $nomor = '62' . substr($nomor, 1);
}

// LINK WHATSAPP
$link = "https://api.whatsapp.com/send?phone=".$nomor."&text=".urlencode($pesan);

// KIRIM KE VIEW PAGE
$result["wa_url"] = $link;
